import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"太和殿","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/taihe-dian.md","filePath":"landmarks/forbidden-city/taihe-dian.md","lastUpdated":1784720050000}'),l={name:"landmarks/forbidden-city/taihe-dian.md"};function n(s,t,i,d,g,u){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="太和殿" tabindex="-1">太和殿 <a class="header-anchor" href="#太和殿" aria-label="Permalink to &quot;太和殿&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1763058075410-d86b870594af?w=1200&amp;q=80" alt="太和殿"></p><blockquote><p>金銮高踞，万殿之尊。这里是中国古代建筑的最高规格，也是皇权天命的实体化身。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>太和殿，俗称&quot;金銮殿&quot;，是紫禁城外朝三大殿之首，也是中国现存体量最大、等级最高的木结构大殿。它矗立在三层汉白玉须弥座台基之上，通高35.05米，面阔十一间，进深五间，建筑面积达2377平方米——在中国古建筑的等级序列中，&quot;十一间&quot;是绝无仅有的孤例，太和殿是唯一的。</p><p>明清两代，凡遇皇帝登基、大婚、册立皇后、命将出征，以及元旦、冬至、万寿节三大朝贺，均在太和殿举行最隆重的典礼。这里不处理日常政务，而是纯粹的国家礼仪空间——每一次大殿门开，都意味着帝国最重大的时刻到来。</p><p>太和殿始建于明永乐十八年（1420年），初名&quot;奉天殿&quot;，嘉靖年间改名&quot;皇极殿&quot;，清顺治二年（1645年）定名&quot;太和殿&quot;，取《周易》&quot;保合太和&quot;之意。现存建筑为清康熙三十四年（1695年）重建。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>面阔</strong></td><td style="text-align:left;">十一间，63.96米</td></tr><tr><td style="text-align:left;"><strong>进深</strong></td><td style="text-align:left;">五间，37.17米</td></tr><tr><td style="text-align:left;"><strong>通高</strong></td><td style="text-align:left;">35.05米（含三层台基）</td></tr><tr><td style="text-align:left;"><strong>建筑面积</strong></td><td style="text-align:left;">2377平方米</td></tr><tr><td style="text-align:left;"><strong>屋顶形制</strong></td><td style="text-align:left;">重檐庑殿顶（中国古建筑最高等级）</td></tr><tr><td style="text-align:left;"><strong>蟠龙金柱</strong></td><td style="text-align:left;">殿内72根（其中6根为沥粉贴金蟠龙柱）</td></tr><tr><td style="text-align:left;"><strong>殿前广场</strong></td><td style="text-align:left;">约25000平方米，可容万人朝贺</td></tr><tr><td style="text-align:left;"><strong>台基螭首</strong></td><td style="text-align:left;">三层须弥座共1142个螭首排水口</td></tr></tbody></table><p>太和殿的建筑语言处处彰显&quot;至高无上&quot;：屋顶采用最高等级的<strong>重檐庑殿顶</strong>，正脊两端安放中国现存最大的琉璃鸱吻（高3.4米）；檐角走兽多达十只（龙、凤、狮、天马、海马、狻猊、押鱼、獬豸、斗牛、行什），加一位骑凤仙人，是全国古建中走兽数量唯一的&quot;十样俱全&quot;——其他任何建筑最多只能用九只。</p><p>殿内的核心是那把<strong>金漆雕龙宝座</strong>（俗称&quot;龙椅&quot;），高约1.7米，髹金漆、雕蟠龙，是明代嘉靖年间遗物。宝座上方悬挂&quot;建极绑猷&quot;匾额（乾隆御笔），头顶是深邃的<strong>蟠龙藻井</strong>——一条巨龙从井底倒悬而下，口衔宝珠，即传说中的&quot;轩辕镜&quot;。殿内六根沥粉贴金蟠龙柱环绕宝座，与藻井金龙上下呼应，构成一个金碧辉煌的权力圣殿。</p><p>殿外三层汉白玉须弥座台基，栏板望柱雕龙刻凤，1142个螭首排水口在暴雨时会形成&quot;千龙吐水&quot;的壮观景象。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="李自成的火与康熙的重建" tabindex="-1">李自成的火与康熙的重建 <a class="header-anchor" href="#李自成的火与康熙的重建" aria-label="Permalink to &quot;李自成的火与康熙的重建&quot;">​</a></h3><p>明末崇祯十七年（1644年），李自成攻入北京，撤离前纵火焚烧紫禁城，太和殿（时称皇极殿）化为灰烬。清军入关后，顺治帝在残破的宫城中即位，直到康熙年间才得以重建。康熙三十四年（1695年），太和殿重建工程历时数年完工，我们今天看到的太和殿，正是那次重建的成果。它比明代原版略小（明奉天店面阔三十丈），但依然冠绝天下。</p><h3 id="袁世凯的-龙椅-闹剧" tabindex="-1">袁世凯的&quot;龙椅&quot;闹剧 <a class="header-anchor" href="#袁世凯的-龙椅-闹剧" aria-label="Permalink to &quot;袁世凯的&quot;龙椅&quot;闹剧&quot;">​</a></h3><p>1915年，袁世凯复辟称帝，嫌太和殿的明代龙椅&quot;不够气派&quot;，竟命人搬走原椅，换上一把中西合璧的高背大椅。那把不伦不类的椅子很快随着帝制覆灭被移走，明代龙椅却不知所踪。直到1959年，文物专家朱家溍在一处库房角落里发现了残破的原椅，经修复后重新安放回太和殿——如今游客透过殿门望见的龙椅，正是那把失而复得的明代真品。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>金漆雕龙宝座与蟠龙藻井</strong>：透过殿门向内望去，龙椅、金柱、藻井、轩辕镜层层纵深，是紫禁城最震撼的视觉中轴线。</li><li><strong>十只檐角走兽</strong>：绕到殿侧仰望檐角，数一数全国唯一的&quot;十样俱全&quot;脊兽队列。</li><li><strong>千龙吐水</strong>：若恰逢暴雨，三层台基的1142个螭首同时喷水，是太和殿最难得的奇景。</li><li><strong>殿前广场的尺度</strong>：站在2.5万平方米的空旷广场上仰望大殿，体会&quot;万人朝贺&quot;的空间压迫感。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>最佳观赏点</strong>：太和门内的金水桥畔是拍摄大殿全景的经典机位；清晨开馆时广场空旷，光线从东南斜照，最显恢宏。</li><li><strong>只能外观</strong>：太和殿内部不对外开放，游客只能在殿门外隔栏观赏，建议带望远镜或长焦镜头看清藻井细节。</li><li><strong>人最多的时段</strong>：10:00-14:00是太和殿广场人流高峰，想拍空镜请赶在8:30开馆后直奔此处。</li><li><strong>别错过铜器</strong>：殿前月台上的日晷、嘉量、铜龟、铜鹤，是皇权&quot;授时&quot;与&quot;度量&quot;的象征，值得细看。</li></ul><hr><p><strong>📍 位置</strong>：外朝中轴线核心，太和门内第一座大殿 <strong>⏱️ 建议游览</strong>：30-40分钟 <strong>🔗 上一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/wumen.html">午门</a><strong>🔗 下一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/zhonghe-dian.html">中和殿</a><strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',23)])])}const f=a(l,[["render",n]]);export{q as __pageData,f as default};
